function detail(title, body){
  const modal=document.createElement('div'); modal.className='modal show'; modal.innerHTML=`<div class="modal-box detail-box"><button class="modal-close">×</button><h2>${title}</h2><div class="detail-content">${body}</div><button class="primary full modal-close-action">知道了</button></div>`;
  document.body.appendChild(modal); modal.querySelectorAll('.modal-close,.modal-close-action').forEach((b)=>b.addEventListener('click',()=>modal.remove()));
}
document.querySelector('.icon-btn:not(.notification)')?.addEventListener('click',()=>{const q=prompt('搜索系统功能或企业名称'); if(q) showToast(`正在搜索：${q}`);});
document.querySelector('.notification')?.addEventListener('click',()=>go('message'));
