const workerInput=document.querySelector('#page-workers .filterbar input');
const workerRows=[...document.querySelectorAll('#page-workers tbody tr')];
function filterWorkers(){const q=(workerInput?.value||'').toLowerCase(); const status=document.querySelector('#page-workers .filterbar select')?.value||'全部状态'; workerRows.forEach(row=>{const text=row.textContent.toLowerCase(); const statusMatch=status==='全部状态'||(status==='在保'&&text.includes('在保'))||(status==='待审核'&&text.includes('待审核'))||(status==='已离职'&&text.includes('离职')); row.style.display=text.includes(q)&&statusMatch?'':'none';});}
document.querySelector('#page-workers .filterbar .outline')?.addEventListener('click',()=>{filterWorkers();showToast('筛选条件已应用')}); workerInput?.addEventListener('keydown',(e)=>{if(e.key==='Enter')filterWorkers()});
document.querySelector('#page-workers .filterbar select')?.addEventListener('change',filterWorkers);
document.querySelector('#page-workers thead input')?.addEventListener('change',(e)=>document.querySelectorAll('#page-workers tbody input[type=checkbox]').forEach((x)=>x.checked=e.target.checked));
document.querySelector('#page-workers .filterbar .outline:last-child')?.addEventListener('click',()=>{const rows=workerRows.filter(r=>r.style.display!=='none'); const csv=['姓名,手机号,劳动关系单位,保险方案,状态,加入时间',...rows.map(r=>[...r.querySelectorAll('td')].slice(1,6).map(x=>`"${x.innerText.replaceAll('"','""')}"`).join(','))].join('\n'); const url=URL.createObjectURL(new Blob(['\ufeff'+csv],{type:'text/csv'})); const a=document.createElement('a'); a.href=url; a.download='投保人员名单.csv'; a.click(); URL.revokeObjectURL(url); showToast('员工名单已导出');});
document.querySelectorAll('#page-workers tbody td:last-child a').forEach((a,i)=>a.addEventListener('click',()=>{const row=a.closest('tr'); const person=row.querySelector('.person b').textContent; if(a.textContent==='查看') detail(`投保人员 · ${person}`,`<p>当前状态：<b class="status on">在保</b></p><p>劳动关系单位：${row.children[2].textContent}</p><p>保险方案：${row.children[3].textContent}</p><p>加入时间：${row.children[5].textContent}</p>`); else {showToast(`已进入 ${person} 的编辑模式`); row.querySelector('.person b').style.color='var(--blue)';}}));
document.querySelectorAll('.pagination button').forEach((b)=>b.addEventListener('click',()=>{if(!b.textContent.includes('…')){document.querySelectorAll('.pagination button').forEach(x=>x.classList.remove('active'));b.classList.add('active');showToast(`已切换到第 ${b.textContent} 页`);}}));
document.querySelectorAll('#page-insurance .plan button').forEach((b)=>b.addEventListener('click',()=>detail('保险方案详情',`<p>方案：团体意外险 · 标准版</p><p>保障范围：意外身故 / 伤残、意外医疗、快速理赔</p><p>适用职业：1-4 类</p><p>操作将生成待审核的开通申请，确认后由运营人员复核。</p>`)));
document.querySelectorAll('.todo-item').forEach((item)=>item.addEventListener('click',()=>{const text=item.querySelector('b')?.textContent||''; if(text.includes('保单'))go('policy'); else if(text.includes('员工'))go('workers'); else if(text.includes('发票'))go('billing'); else showToast('该事项已记录');}));
document.querySelectorAll('.placeholder .outline').forEach((b)=>b.addEventListener('click',()=>detail('操作指引','<p>先创建或导入业务数据，再使用筛选、批量操作、导出和详情功能。所有高风险操作都会要求二次确认，并写入审计日志。</p>')));
document.querySelectorAll('.page-heading .primary').forEach((b)=>b.addEventListener('click',()=>{if(b.closest('#page-workers'))document.querySelector('[data-action="add-worker"]').click();else showToast('新增流程已打开，请按页面提示完成填写');}));
document.querySelector('[data-action="new-plan"]')?.addEventListener('click',()=>document.querySelector('#plan-form input[name="insurer"]')?.focus());
document.querySelector('#plan-form')?.addEventListener('submit',async(e)=>{e.preventDefault();if(e.currentTarget.dataset.saving==='1')return;const form=e.currentTarget;const submit=form.querySelector('button[type="submit"]');const original=submit.textContent;const wasEditing=Boolean(editingPlanId);form.dataset.saving='1';submit.disabled=true;submit.textContent='保存中…';const values=new FormData(form);const data=Object.fromEntries(values.entries());data.price=Number(data.price);data.commission_rate=Number(data.commission_rate);try{const saved=await api(wasEditing?`/plans/${editingPlanId}`:'/plans',{method:wasEditing?'PATCH':'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});form.reset();editingPlanId=null;showToast(`方案“${saved.name}”已${wasEditing?'修改':'保存'}`);submit.textContent='保存方案';await loadPlans();document.querySelector('#plan-rows')?.closest('.plan-table')?.scrollIntoView({behavior:'smooth',block:'start'});}catch(err){showToast(`保存失败：${err.message}`);}finally{form.dataset.saving='0';submit.disabled=false;if(!editingPlanId&&!wasEditing)submit.textContent=original;}});
document.querySelector('[data-page="insurers"]')?.addEventListener('click',()=>setTimeout(loadPlans,0));
if(authToken()) loadPlans();
document.querySelectorAll('#page-workers tbody tr td:last-child').forEach((cell)=>{if(!cell.querySelector('[data-worker-action]')){const a=document.createElement('a');a.href='#';a.dataset.workerAction='toggle';a.textContent='停保';cell.appendChild(a);}});
document.addEventListener('click',(e)=>{const action=e.target.closest('[data-worker-action]');if(!action)return;e.preventDefault();const row=action.closest('tr');const name=row?.querySelector('.person b')?.textContent||'员工';if(confirm(`确认对${name}执行停保？`)){action.textContent=action.textContent==='停保'?'恢复':'停保';showToast(`${name}状态已更新`);}},true);
const agentObserver=new MutationObserver(()=>{document.querySelectorAll('#agent-rows tr').forEach(row=>{const cell=row.lastElementChild;if(cell&&!cell.querySelector('[data-agent-commission]')){const a=document.createElement('a');a.href='#';a.dataset.agentCommission='1';a.textContent='关联方案';cell.appendChild(a);}});});agentObserver.observe(document.body,{childList:true});document.addEventListener('click',(e)=>{const a=e.target.closest('[data-agent-commission]');if(!a)return;e.preventDefault();showToast('请先新增投保单位和保险方案，再配置业务员佣金关联');},true);
const agentBusinessLabelObserver=new MutationObserver(()=>document.querySelectorAll('[data-agent-commission]').forEach(a=>a.textContent='业务'));agentBusinessLabelObserver.observe(document.body,{childList:true});
const agentFormObserver=new MutationObserver(()=>{const form=document.querySelector('#agent-form');if(!form||form.dataset.cleaned)return;form.dataset.cleaned='1';form.querySelector('[name="commission_rate"]')?.closest('label')?.remove();const button=document.createElement('button');button.type='button';button.className='outline';button.textContent='新增业务';button.dataset.agentBusiness='1';form.querySelector('.form-actions')?.appendChild(button);});agentFormObserver.observe(document.body,{childList:true});
document.addEventListener('submit',async(e)=>{if(e.target.id!=='agent-form')return;e.preventDefault();e.stopImmediatePropagation();const form=e.target,btn=form.querySelector('button[type="submit"]');const data=Object.fromEntries(new FormData(form));if(!data.name?.trim()||!data.username?.trim()||!data.password?.trim()){showToast('请填写姓名、登录账号和初始密码');return;}data.commission_rate=.15;btn.disabled=true;btn.textContent='保存中…';try{await api('/agents',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});form.reset();showToast('业务员已保存');renderAgents();}catch(err){showToast(`保存失败：${err.message}`);btn.disabled=false;btn.textContent='保存业务员';}},true);
async function openCommissionForm(agentId){try{const [enterprises,plans]=await Promise.all([api('/enterprises'),api('/plans')]);const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box"><button class="modal-close">×</button><h2>关联佣金规则</h2><p>将业务员佣金绑定到具体投保单位和产品方案</p><form><label>投保单位<select name="enterprise_id" required>${enterprises.map(x=>`<option value="${x.id}">${esc(x.name)}</option>`).join('')}</select></label><label>产品方案<select name="plan_id" required>${plans.map(x=>`<option value="${x.id}">${esc(x.insurer)} · ${esc(x.name)}</option>`).join('')}</select></label><label>佣金比例<input name="rate" type="number" min="0" max="1" step="0.01" value="0.15" required></label><button class="primary full" type="submit">保存佣金关联</button><div class="auth-error"></div></form></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async(e)=>{e.preventDefault();const data=Object.fromEntries(new FormData(e.currentTarget));data.agent_id=Number(agentId);data.enterprise_id=Number(data.enterprise_id);data.plan_id=Number(data.plan_id);data.rate=Number(data.rate);try{await api('/agent-commissions',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});modal.remove();showToast('佣金已关联到投保单位和产品方案');}catch(err){e.currentTarget.querySelector('.auth-error').textContent=err.message;}};}catch(err){showToast(err.message);}}
document.addEventListener('click',async(e)=>{const a=e.target.closest('[data-agent-commission]');if(!a)return;e.preventDefault();const name=a.closest('tr')?.querySelector('td')?.textContent.trim();const agents=await api('/agents');const agent=agents.find(x=>x.name===name);if(agent)openCommissionForm(agent.id);},true);
document.addEventListener('click',async(e)=>{const a=e.target.closest('[data-agent-business]');if(!a)return;e.preventDefault();openNewBusinessForm();},true);
async function openNewBusinessForm(){try{const [agents,enterprises,plans]=await Promise.all([api('/agents'),api('/enterprises'),api('/plans')]);const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box"><button class="modal-close">×</button><h2>新增业务</h2><p>建立业务员、投保单位和产品方案的佣金关系</p><form><label>业务员<select name="agent_id" required>${agents.map(x=>`<option value="${x.id}">${esc(x.name)}</option>`).join('')}</select></label><label>投保单位<select name="enterprise_id" required>${enterprises.map(x=>`<option value="${x.id}">${esc(x.name)}</option>`).join('')}</select></label><label>产品方案<select name="plan_id" required>${plans.map(x=>`<option value="${x.id}">${esc(x.insurer)} · ${esc(x.name)}</option>`).join('')}</select></label><label>佣金比例<input name="rate" type="number" min="0" max="1" step="0.01" value="0.15" required></label><button class="primary full" type="submit">保存新增业务</button><div class="auth-error"></div></form></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async(e)=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));Object.keys(d).forEach(k=>d[k]=k==='rate'?Number(d[k]):Number(d[k]));try{await api('/agent-commissions',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});modal.remove();showToast('新增业务已保存');if(location.hash.includes('promotion'))renderPromotion();}catch(err){e.currentTarget.querySelector('.auth-error').textContent=err.message;}};}catch(err){showToast(`无法打开新增业务：${err.message}`);}}
async function openNewBusinessForm(){try{const [agents,enterprises,plans]=await Promise.all([api('/agents'),api('/enterprises'),api('/plans')]);const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box"><button class="modal-close">×</button><h2>新增业务</h2><p>选择业务员收益模式</p><form><label>业务员<select name="agent_id" required>${agents.map(x=>`<option value="${x.id}">${esc(x.name)}</option>`).join('')}</select></label><label>投保单位<select name="enterprise_id" required>${enterprises.map(x=>`<option value="${x.id}">${esc(x.name)}</option>`).join('')}</select></label><label>产品方案<select name="plan_id" required>${plans.map(x=>`<option value="${x.id}">${esc(x.insurer)} · ${esc(x.name)}</option>`).join('')}</select></label><label>收益方式<select name="mode" id="business-mode"><option value="rebate">返佣（按保司返佣比例）</option><option value="markup">加价（原始价上增加价）</option></select></label><label>返佣比例<input name="rate" type="number" min="0" max="1" step="0.01" value="0.15"></label><label>加价金额（元/人/月）<input name="markup_amount" type="number" min="0" step="0.01" value="0"></label><button class="primary full" type="submit">保存新增业务</button><div class="auth-error"></div></form></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async(e)=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));d.agent_id=Number(d.agent_id);d.enterprise_id=Number(d.enterprise_id);d.plan_id=Number(d.plan_id);d.rate=Number(d.rate);d.markup_amount=Number(d.markup_amount);if(d.mode==='markup')d.rate=0;try{await api('/agent-commissions',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});modal.remove();showToast('新增业务已保存');if(location.hash.includes('promotion'))renderPromotion();}catch(err){e.currentTarget.querySelector('.auth-error').textContent=err.message;}};}catch(err){showToast(`无法打开新增业务：${err.message}`);}}
async function openCommissionList(){try{const rows=await api('/agent-commissions');const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box detail-box"><button class="modal-close">×</button><h2>业务关系列表</h2><p>业务员、投保单位、产品方案和佣金比例</p><div class="detail-content">${rows.length?rows.map(x=>`<p><b>${esc(x.agent_name)}</b> · ${esc(x.enterprise_name)} · ${esc(x.plan_name)} · ${(Number(x.rate)*100).toFixed(1)}% · ${x.status}</p>`).join(''):'<p>暂无业务关系，请点击“新增业务”添加。</p>'}</div><button class="primary full" id="commission-close">关闭</button></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('#commission-close').onclick=()=>modal.remove();}catch(err){showToast(err.message);}}
const enterpriseFormObserver=new MutationObserver(()=>{document.querySelectorAll('.enterprise-form').forEach(async(form)=>{if(form.querySelector('[name="agent_id"]'))return;const label=document.createElement('label');label.textContent='负责业务员';const select=document.createElement('select');select.name='agent_id';select.innerHTML='<option value="">请选择业务员</option>';try{const agents=await api('/agents');agents.forEach(a=>{const o=document.createElement('option');o.value=a.id;o.textContent=a.name;select.appendChild(o);});}catch(err){}label.appendChild(select);form.insertBefore(label,form.querySelector('button[type="submit"]'));});});enterpriseFormObserver.observe(document.body,{childList:true});
document.addEventListener('submit',async(e)=>{const form=e.target;if(!form.classList.contains('enterprise-form'))return;e.preventDefault();e.stopImmediatePropagation();const data=Object.fromEntries(new FormData(form));data.agent_id=data.agent_id?Number(data.agent_id):null;const btn=form.querySelector('button[type="submit"]');btn.disabled=true;try{const saved=await api('/enterprises',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});form.closest('.modal')?.remove();showToast(`投保单位“${saved.name}”已创建`);renderEnterprises();}catch(err){form.querySelector('.auth-error').textContent=err.message;btn.disabled=false;}},true);
const editEnterpriseObserver=new MutationObserver(async()=>{const heading=[...document.querySelectorAll('.modal-box h2')].find(x=>x.textContent.includes('编辑投保单位'));if(!heading)return;const form=heading.closest('.modal-box')?.querySelector('form');if(!form||form.querySelector('[name="agent_id"]'))return;const label=document.createElement('label');label.textContent='负责业务员';const select=document.createElement('select');select.name='agent_id';select.innerHTML='<option value="">暂不指定</option>';try{const agents=await api('/agents');agents.forEach(x=>{const o=document.createElement('option');o.value=x.id;o.textContent=x.name;select.appendChild(o);});}catch(err){}label.appendChild(select);form.insertBefore(label,form.querySelector('button[type="submit"]'));});editEnterpriseObserver.observe(document.body,{childList:true});
document.addEventListener('submit',async(e)=>{const heading=e.target.closest('.modal-box')?.querySelector('h2');if(!heading||!heading.textContent.includes('编辑投保单位'))return;e.preventDefault();e.stopImmediatePropagation();const data=Object.fromEntries(new FormData(e.target));data.agent_id=data.agent_id?Number(data.agent_id):null;try{const saved=await api(`/enterprises/${e.target.dataset.enterpriseId||''}`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});e.target.closest('.modal')?.remove();showToast(`单位“${saved.name}”已修改`);renderEnterprises();}catch(err){e.target.querySelector('.auth-error').textContent=err.message;}},true);
const editIdObserver=new MutationObserver(async()=>{for(const form of document.querySelectorAll('.modal-box form')){if(!form.dataset.enterpriseId&&form.closest('.modal-box')?.querySelector('h2')?.textContent.includes('编辑投保单位')){try{const all=await api('/enterprises');form.dataset.enterpriseId=all.find(x=>x.name===form.querySelector('[name="name"]')?.value)?.id||'';}catch(err){}}}});editIdObserver.observe(document.body,{childList:true});
const enterpriseColumnObserver=new MutationObserver(async()=>{const rows=document.querySelectorAll('#enterprise-rows tr');const table=document.querySelector('#page-generic .table-panel table');if(!rows.length||!table||rows[0].querySelector('.loading-cell'))return;const head=table.querySelector('thead tr');if(!head.querySelector('[data-agent-column]')){const th=document.createElement('th');th.dataset.agentColumn='1';th.textContent='负责业务员';head.insertBefore(th,head.lastElementChild);}let items=[];try{items=await api('/enterprises')}catch(err){}rows.forEach((row,i)=>{if(row.querySelector('[data-agent-cell]'))return;const td=document.createElement('td');td.dataset.agentCell='1';td.textContent=items[i]?.agent_name||'未分配';row.insertBefore(td,row.lastElementChild);});});enterpriseColumnObserver.observe(document.body,{childList:true});
setTimeout(enhanceEnterpriseList,900);
function enhanceWorkerRelationList(){const table=document.querySelector('#page-workers table');if(!table||table.dataset.relationReady)return;table.dataset.relationReady='1';const head=table.querySelector('thead tr');const ths=['所在企业','实际用工单位','投保岗位','职业类别','被保险人','投保人'];const before=head.children[1];ths.forEach((x)=>{const th=document.createElement('th');th.textContent=x;head.insertBefore(th,before);});table.querySelectorAll('tbody tr').forEach((row)=>{const person=row.querySelector('.person b')?.textContent||'—';const vals=['投保单位待关联','实际用工单位待确认','仓储分拣员','3类',person,'投保单位'];const beforeCell=row.children[1];vals.forEach((x)=>{const td=document.createElement('td');td.textContent=x;row.insertBefore(td,beforeCell);});});}
enhanceWorkerRelationList();
document.addEventListener('click',(e)=>{const a=e.target.closest('#page-workers tbody td:last-child a');if(!a||a.textContent!=='查看')return;e.preventDefault();e.stopImmediatePropagation();const row=a.closest('tr'),person=row.querySelector('.person b')?.textContent||'—';detail(`投保关系 · ${person}`,`<p>所在企业：投保单位待关联</p><p>实际用工单位：实际用工单位待确认</p><p>投保岗位：仓储分拣员</p><p>职业类别：3类</p><p>被保险人：${esc(person)}</p><p>投保人：投保单位</p><p>产品方案：${esc(row.children[10]?.textContent||'待绑定')}</p>`);},true);
async function openEnterpriseProducts(item){try{const rows=await api(`/enterprises/${item.id}/products`);const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box detail-box product-list-modal"><button class="modal-close">×</button><h2>参保产品 · ${esc(item.name)}</h2><p>查看该投保单位绑定的全部产品和业务关系</p><div class="module-stats mini-product-stats"><div><span>产品数量</span><b>${rows.length}</b></div><div><span>参保人数</span><b>${rows.reduce((n,x)=>n+Number(x.insured_count||0),0)}</b></div><div><span>保费总额</span><b>¥ ${rows.reduce((n,x)=>n+Number(x.premium_total||0),0).toFixed(2)}</b></div></div><div class="filterbar"><input id="product-search" placeholder="搜索产品、保险公司或业务员"><button class="outline" id="product-search-btn">搜索</button><button class="primary" id="product-add-btn">＋ 新增关联</button></div><div class="detail-content product-table-wrap">${rows.length?`<table class="mini-table product-table"><thead><tr><th>保险公司</th><th>产品方案</th><th>业务员</th><th>佣金比例</th><th>参保人数</th><th>保费总额</th><th>状态</th><th>操作</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.insurer)}</td><td>${esc(x.product)}</td><td>${esc(x.agent||'未分配')}</td><td>${Number(x.commission_rate)*100}%</td><td>${x.insured_count}</td><td>¥ ${Number(x.premium_total).toFixed(2)}</td><td>${esc(x.status)}</td><td><a class="product-detail-action">查看</a></td></tr>`).join('')}</tbody></table>`:'<p class="product-empty">该单位暂无参保产品，请新增业务关联。</p>'}</div><div class="list-footer"><span>共 ${rows.length} 条记录 · 当前第 1 页</span><label>每页 10 条</label></div></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();const search=modal.querySelector('#product-search');const filter=()=>{const q=search.value.toLowerCase();modal.querySelectorAll('.product-table tbody tr').forEach(r=>r.style.display=r.textContent.toLowerCase().includes(q)?'':'none');};modal.querySelector('#product-search-btn').onclick=filter;search?.addEventListener('keydown',e=>{if(e.key==='Enter')filter();});modal.querySelector('#product-add-btn').onclick=()=>{modal.remove();showToast('请从业务员管理 → 业务中新增该单位的产品关联');};modal.querySelectorAll('.product-detail-action').forEach(a=>a.onclick=()=>showToast('已打开产品关联详情'));}catch(err){showToast(err.message);}}
async function renderProducts(){const root=document.querySelector('#page-insurance');if(!root)return;try{const plans=await api('/plans');root.innerHTML=`<div class="page-heading"><div><div class="kicker">PRODUCT MANAGEMENT</div><h1>保险产品管理</h1><p>保险公司方案库 · 产品价格 · 职业类别 · 返佣和状态</p></div><button class="primary" data-page="insurers">＋ 新增产品方案</button></div><div class="module-stats"><div><span>产品方案</span><b>${plans.length}</b></div><div><span>在售方案</span><b>${plans.filter(x=>x.status==='active').length}</b></div><div><span>保险公司</span><b>${new Set(plans.map(x=>x.insurer)).size}</b></div></div><div class="filterbar"><input id="plan-search" placeholder="搜索保险公司或产品名称"><button class="outline" id="plan-filter">搜索</button><button class="outline" data-page="insurers">进入方案维护</button></div><div class="panel table-panel"><div class="table-caption"><b>产品方案列表 <small>共 ${plans.length} 条记录</small></b><span>数据来自保险公司方案库</span></div><table><thead><tr><th>保险公司</th><th>产品方案</th><th>保障范围</th><th>职业类别</th><th>价格</th><th>返佣</th><th>状态</th><th>操作</th></tr></thead><tbody id="product-rows">${plans.map(x=>`<tr><td>${esc(x.insurer)}</td><td><b>${esc(x.name)}</b></td><td>${esc(x.coverage)}</td><td>${esc(x.occupation_classes)}</td><td>¥ ${Number(x.price).toFixed(2)}</td><td>${Number(x.commission_rate)*100}%</td><td><label class="status ${x.status==='active'?'on':'off'}">● ${x.status==='active'?'在售':'已暂停'}</label></td><td><a data-page="insurers">管理</a></td></tr>`).join('')||'<tr><td colspan="8" class="loading-cell">暂无产品，请先录入方案</td></tr>'}</tbody></table><div class="list-footer"><span>共 ${plans.length} 条记录 · 当前第 1 页</span><label>每页 10 条</label></div></div>`;root.querySelector('#plan-filter').onclick=()=>{const q=root.querySelector('#plan-search').value.toLowerCase();root.querySelectorAll('#product-rows tr').forEach(r=>r.style.display=r.textContent.toLowerCase().includes(q)?'':'none');showToast('产品筛选已完成');};root.querySelectorAll('[data-page]').forEach(a=>a.onclick=(e)=>{e.preventDefault();go(a.dataset.page);});}catch(err){showToast(err.message);}}
const productTierObserver=new MutationObserver(async()=>{const rows=document.querySelectorAll('#product-rows tr');if(!rows.length||rows[0].querySelector('.loading-cell'))return;const plans=await api('/plans').catch(()=>[]);rows.forEach((row,i)=>{const cell=row.lastElementChild;if(cell&&!cell.querySelector('[data-tier-action]')){const a=document.createElement('a');a.href='#';a.dataset.tierAction=plans[i]?.id||'';a.textContent='类别价格';cell.appendChild(a);}});});productTierObserver.observe(document.body,{childList:true,subtree:true});
document.addEventListener('click',(e)=>{const a=e.target.closest('[data-tier-action]');if(!a)return;e.preventDefault();openPlanTiers(Number(a.dataset.tierAction));},true);
async function openPlanTiers(planId){const plans=await api('/plans');const plan=plans.find(x=>x.id===planId);const tiers=await api(`/plan-tiers?plan_id=${planId}`);const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box detail-box"><button class="modal-close">×</button><h2>类别价格 · ${esc(plan?.name||'')}</h2><p>同一保险方案按职业类别维护不同收费标准</p><div class="detail-content">${tiers.length?tiers.map(x=>`<p><b>${x.occupation_class}</b> · ¥ ${Number(x.price).toFixed(2)} / 人 / 月 · ${esc(x.coverage||'继承主方案保障')}</p>`).join(''):'<p>尚未设置类别价格</p>'}</div><button class="primary full" id="tier-add">＋ 新增类别价格</button></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('#tier-add').onclick=()=>openTierCreate(plan);}
function openTierCreate(plan){const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box"><button class="modal-close">×</button><h2>新增保险类别价格</h2><p>${esc(plan.name)}</p><form><label>保险类别<select name="occupation_class"><option>1-3类</option><option>4类</option><option>5类</option><option>超5类</option></select></label><label>价格（元/人/月）<input name="price" type="number" min="0" step="0.01" required></label><label>类别保障说明<textarea name="coverage" placeholder="可覆盖主方案保障范围"></textarea></label><button class="primary full" type="submit">保存类别价格</button><div class="auth-error"></div></form></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async(e)=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));d.plan_id=plan.id;d.price=Number(d.price);try{await api('/plan-tiers',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});modal.remove();showToast('保险类别价格已保存');}catch(err){e.currentTarget.querySelector('.auth-error').textContent=err.message;}};}
async function renderPolicies(){const root=document.querySelector('#page-generic');try{const rows=await api('/policies');root.innerHTML=`<div class="page-heading"><div><div class="kicker">POLICY MANAGEMENT</div><h1>保单管理</h1><p>按保险公司、产品方案和投保单位查看保单状态</p></div><button class="primary" id="policy-export">导出保单</button></div><div class="module-stats"><div><span>保单总数</span><b>${rows.length}</b></div><div><span>生效中</span><b>${rows.filter(x=>x.status==='active').length}</b></div><div><span>保费总额</span><b>¥ ${rows.reduce((n,x)=>n+Number(x.premium||0),0).toFixed(2)}</b></div></div><div class="filterbar"><input id="policy-search" placeholder="搜索保单号、投保单位或产品"><button class="outline" id="policy-filter">搜索</button></div><div class="panel table-panel"><div class="table-caption"><b>保单列表 <small>共 ${rows.length} 条记录</small></b><span>保司方案实时关联</span></div><table><thead><tr><th>保单号</th><th>投保单位</th><th>保险公司</th><th>产品方案</th><th>保费</th><th>生效日期</th><th>状态</th><th>操作</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.policy_no)}</td><td>${esc(x.enterprise_name)}</td><td>${esc(x.insurer)}</td><td>${esc(x.plan_name)}</td><td>¥ ${Number(x.premium).toFixed(2)}</td><td>${esc(x.start_date)}</td><td><label class="status ${x.status==='active'?'on':'wait'}">● ${esc(x.status)}</label></td><td><a class="policy-detail">查看</a></td></tr>`).join('')||'<tr><td colspan="8" class="loading-cell">暂无保单记录</td></tr>'}</tbody></table><div class="list-footer"><span>共 ${rows.length} 条记录 · 当前第 1 页</span><label>每页 10 条</label></div></div>`;root.querySelector('#policy-filter').onclick=()=>{const q=root.querySelector('#policy-search').value.toLowerCase();root.querySelectorAll('tbody tr').forEach(r=>r.style.display=r.textContent.toLowerCase().includes(q)?'':'none');};root.querySelector('#policy-export').onclick=()=>showToast('保单数据已准备导出');}catch(err){showToast(err.message);}}
async function renderPromotion(){const root=document.querySelector('#page-generic');try{const rows=await api('/agent-commissions');const max=rows.length?Math.max(...rows.map(x=>Number(x.rate))):0;const avg=rows.length?rows.reduce((n,x)=>n+Number(x.rate),0)/rows.length:0;root.innerHTML=`<div class="page-heading"><div><div class="kicker">PROMOTION & COMMISSION</div><h1>推广与佣金</h1><p>业务员推广关系、单位产品关联和佣金返还规则</p></div><button class="primary" data-agent-business="1">＋ 新增业务</button></div><div class="module-stats"><div><span>推广业务关系</span><b>${rows.length}</b></div><div><span>佣金最高比例</span><b class="up">${(max*100).toFixed(1)}%</b></div><div><span>平均佣金比例</span><b>${(avg*100).toFixed(1)}%</b></div></div><div class="filterbar"><input id="commission-search" placeholder="搜索业务员、投保单位或产品方案"><select id="commission-rate"><option value="">全部佣金比例</option><option value="0.2">20% 及以上</option><option value="0.15">15% 及以上</option></select><button class="outline" id="commission-filter">筛选</button><button class="outline" id="commission-export">导出佣金</button></div><div class="panel table-panel"><div class="table-caption"><b>业务佣金关联列表 <small>共 ${rows.length} 条记录</small></b><span>最高返佣：${(max*100).toFixed(1)}%</span></div><table><thead><tr><th>业务员</th><th>投保单位</th><th>产品方案</th><th>佣金比例</th><th>佣金金额</th><th>状态</th><th>操作</th></tr></thead><tbody id="commission-rows">${rows.map(x=>`<tr><td><b>${esc(x.agent_name)}</b></td><td>${esc(x.enterprise_name)}</td><td>${esc(x.plan_name)}</td><td class="commission-rate">${(Number(x.rate)*100).toFixed(1)}%</td><td>¥ 0.00</td><td><label class="status ${x.status==='active'?'on':'off'}">● ${x.status==='active'?'推广中':'已暂停'}</label></td><td><a class="commission-view">查看</a></td></tr>`).join('')||'<tr><td colspan="7" class="loading-cell">暂无推广业务，请点击新增业务</td></tr>'}</tbody></table><div class="list-footer"><span>共 ${rows.length} 条记录 · 当前第 1 页</span><label>每页 10 条</label></div></div>`;root.querySelector('#commission-filter').onclick=()=>{const q=root.querySelector('#commission-search').value.toLowerCase(),min=Number(root.querySelector('#commission-rate').value||0);root.querySelectorAll('#commission-rows tr').forEach(r=>{const rate=parseFloat(r.querySelector('.commission-rate')?.textContent||0)/100;r.style.display=r.textContent.toLowerCase().includes(q)&&rate>=min?'':'none';});};root.querySelector('#commission-export').onclick=()=>showToast('佣金明细已准备导出');root.querySelectorAll('.commission-view').forEach(a=>a.onclick=()=>showToast('已打开业务佣金详情'));}catch(err){showToast(err.message);}}
const commissionEditObserver=new MutationObserver(()=>{document.querySelectorAll('#commission-rows tr').forEach((row,i)=>{const cell=row.lastElementChild;if(cell&&!cell.querySelector('[data-commission-edit]')){const a=document.createElement('a');a.href='#';a.dataset.commissionEdit=String(i);a.textContent='编辑';cell.appendChild(a);}});});commissionEditObserver.observe(document.body,{childList:true,subtree:true});
const commissionMarkupObserver=new MutationObserver(async()=>{const rows=document.querySelectorAll('#commission-rows tr');const table=document.querySelector('#commission-rows')?.closest('table');if(!rows.length||!table||rows[0].querySelector('.loading-cell')||table.querySelector('[data-markup-column]'))return;const th=document.createElement('th');th.dataset.markupColumn='1';th.textContent='加价金额';table.querySelector('thead tr').insertBefore(th,table.querySelector('thead tr').lastElementChild);const data=await api('/agent-commissions').catch(()=>[]);rows.forEach((row,i)=>{const td=document.createElement('td');td.textContent=`¥ ${Number(data[i]?.markup_amount||0).toFixed(2)}`;row.insertBefore(td,row.lastElementChild);});});commissionMarkupObserver.observe(document.body,{childList:true,subtree:true});
document.addEventListener('click',async(e)=>{const a=e.target.closest('[data-commission-edit]');if(!a)return;e.preventDefault();const rows=await api('/agent-commissions');const item=rows[Number(a.dataset.commissionEdit)];if(item)openCommissionEdit(item);},true);
function openCommissionEdit(item){const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box"><button class="modal-close">×</button><h2>编辑佣金关系</h2><p>${esc(item.agent_name)} · ${esc(item.enterprise_name)} · ${esc(item.plan_name)}</p><form><label>收益方式<select name="mode"><option value="rebate" ${item.mode==='rebate'?'selected':''}>返佣</option><option value="markup" ${item.mode==='markup'?'selected':''}>加价</option></select></label><label>返佣比例<input name="rate" type="number" min="0" max="1" step="0.01" value="${item.rate||0}"></label><label>加价金额<input name="markup_amount" type="number" min="0" step="0.01" value="${item.markup_amount||0}"></label><label>状态<select name="status"><option value="active" ${item.status==='active'?'selected':''}>推广中</option><option value="paused" ${item.status==='paused'?'selected':''}>已暂停</option></select></label><button class="primary full" type="submit">保存修改</button><div class="auth-error"></div></form></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async(e)=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));d.rate=Number(d.rate);d.markup_amount=Number(d.markup_amount);if(d.mode==='markup')d.rate=0;try{await api(`/agent-commissions/${item.id}`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});modal.remove();showToast('佣金关系已修改');renderPromotion();}catch(err){e.currentTarget.querySelector('.auth-error').textContent=err.message;}};}
async function renderEnrollmentCenter(){const root=document.querySelector('#page-generic');const batches=[{no:'ENR-20260710-001',insurer:'平安财险',type:'参保',count:0,time:'待生成',status:'待生成'},{no:'TER-20260710-002',insurer:'太平洋产险',type:'停保',count:0,time:'待生成',status:'待发送'}];root.innerHTML=`<div class="page-heading"><div><div class="kicker">ENROLLMENT CENTER</div><h1>参停保中心</h1><p>按保险公司生成参保/停保名单，匹配保司格式并发送回执</p></div><button class="primary" id="batch-create">＋ 生成名单批次</button></div><div class="module-stats"><div><span>待发送批次</span><b>${batches.filter(x=>x.status==='待发送').length}</b></div><div><span>今日参停保人数</span><b>${batches.reduce((n,x)=>n+x.count,0)}</b></div><div><span>发送成功率</span><b class="up">100%</b></div></div><div class="filterbar"><input id="batch-search" placeholder="搜索批次号或保险公司"><select id="batch-type"><option value="">全部类型</option><option>参保</option><option>停保</option></select><button class="outline" id="batch-filter">筛选</button></div><div class="panel table-panel"><div class="table-caption"><b>名单批次列表 <small>共 ${batches.length} 条记录</small></b><span>支持导出、邮件发送和回执跟踪</span></div><table><thead><tr><th>批次号</th><th>保险公司</th><th>类型</th><th>人数</th><th>名单格式</th><th>生成时间</th><th>状态</th><th>操作</th></tr></thead><tbody>${batches.map(x=>`<tr><td>${x.no}</td><td>${x.insurer}</td><td>${x.type}</td><td>${x.count}</td><td>保司专属 Excel</td><td>${x.time}</td><td><label class="status ${x.status==='待发送'?'wait':'off'}">● ${x.status}</label></td><td><a class="batch-export">导出</a><a class="batch-send">发送</a><a class="batch-receipt">回执</a></td></tr>`).join('')}</tbody></table><div class="list-footer"><span>共 ${batches.length} 条记录 · 当前第 1 页</span><label>每页 10 条</label></div></div>`;root.querySelector('#batch-create').onclick=()=>showToast('已生成新的参停保名单批次，等待选择保险公司');root.querySelector('#batch-filter').onclick=()=>{const q=root.querySelector('#batch-search').value.toLowerCase(),t=root.querySelector('#batch-type').value;root.querySelectorAll('tbody tr').forEach(r=>r.style.display=r.textContent.toLowerCase().includes(q)&&(!t||r.textContent.includes(t))?'':'none');};root.querySelectorAll('.batch-export').forEach(a=>a.onclick=()=>showToast('保司格式名单已准备导出'));root.querySelectorAll('.batch-send').forEach(a=>a.onclick=()=>confirm('确认发送至保险公司邮箱？')&&showToast('已进入邮件发送队列'));root.querySelectorAll('.batch-receipt').forEach(a=>a.onclick=()=>showToast('暂无保司回执'));}
async function renderDataScreen(){const root=document.querySelector('#page-screen');try{const rows=await api('/screen/products');const people=rows.reduce((n,x)=>n+x.insured_count,0),units=rows.reduce((n,x)=>n+x.enterprise_count,0),premium=rows.reduce((n,x)=>n+x.premium_total,0);root.innerHTML=`<div class="page-heading"><div><div class="kicker">OPERATING DATA SCREEN</div><h1>经营数据大屏</h1><p>产品级在保人数、参保单位和累计保费实时汇总</p></div><span class="screen-time">● 实时数据</span></div><div class="screen-cards"><div><span>参保员工</span><b>${people}</b><em>产品汇总</em></div><div><span>参保单位</span><b>${units}</b><em>去重单位数</em></div><div><span>累计保费</span><b>¥ ${premium.toFixed(2)}</b><em>保单汇总</em></div><div><span>产品方案</span><b>${rows.length}</b><em>来自方案库</em></div></div><div class="panel table-panel"><div class="table-caption"><b>产品经营明细 <small>共 ${rows.length} 条</small></b><span>实时计算</span></div><table><thead><tr><th>保险公司</th><th>产品方案</th><th>在保人数</th><th>参保单位数量</th><th>保单数</th><th>累计保费</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.insurer)}</td><td><b>${esc(x.product)}</b></td><td>${x.insured_count}</td><td>${x.enterprise_count}</td><td>${x.policy_count}</td><td>¥ ${Number(x.premium_total).toFixed(2)}</td></tr>`).join('')||'<tr><td colspan="6" class="loading-cell">暂无真实产品数据</td></tr>'}</tbody></table></div><div class="screen-grid"><div class="panel big-chart"><div class="panel-title"><h2>参保人数趋势</h2><small>按月统计</small></div><div class="line-chart"><div class="line-fill"></div><div class="line-path"></div><div class="chart-labels"><span>1月</span><span>2月</span><span>3月</span><span>4月</span><span>5月</span><span>6月</span></div></div></div><div class="panel ring-panel"><h2>产品保费占比</h2><div class="ring"><div><b>¥${premium.toFixed(0)}</b><small>累计保费</small></div></div><div class="legend">${rows.slice(0,4).map((x,i)=>`<span><i class="dot ${['purple-bg','orange-bg','blue-bg'][i%3]}"></i>${esc(x.product)} <b>¥${Number(x.premium_total).toFixed(0)}</b></span>`).join('')}</div></div></div>`;}catch(err){showToast(err.message);}}
async function renderPositions(){const root=document.querySelector('#page-generic');try{const [positions,enterprises,plans]=await Promise.all([api('/positions'),api('/enterprises'),api('/plans')]);root.innerHTML=`<div class="page-heading"><div><div class="kicker">POSITION MANAGEMENT</div><h1>投保岗位管理</h1><p>岗位、实际用工单位、保险类别与产品方案统一管理</p></div><button class="primary" id="position-add">＋ 新增投保岗位</button></div><div class="module-stats"><div><span>岗位总数</span><b>${positions.length}</b></div><div><span>待核保岗位</span><b>${positions.filter(x=>x.status==='pending').length}</b></div><div><span>已绑定产品</span><b>${positions.filter(x=>x.plan_id).length}</b></div></div><div class="filterbar"><input id="position-search" placeholder="搜索岗位名称或实际用工单位"><select id="position-class"><option value="">全部保险类别</option><option>1-3类</option><option>4类</option><option>5类</option><option>超5类</option></select><button class="outline" id="position-filter">筛选</button></div><div class="panel table-panel"><div class="table-caption"><b>投保岗位列表 <small>共 ${positions.length} 条记录</small></b><span>保险类别：1-3类 / 4类 / 5类 / 超5类</span></div><table><thead><tr><th>岗位名称</th><th>实际用工单位</th><th>保险类别</th><th>绑定产品</th><th>在保人数</th><th>核保状态</th><th>操作</th></tr></thead><tbody>${positions.map(x=>`<tr data-position-id="${x.id}"><td><b>${esc(x.name)}</b></td><td>${esc(x.actual_employer)}</td><td>${esc(x.occupation_class)}</td><td>${x.plan_id||'未绑定'}</td><td>0</td><td><label class="status ${x.status==='approved'?'on':'wait'}">● ${x.status==='approved'?'已通过':'待核保'}</label></td><td><a class="position-edit">编辑</a><a class="position-toggle">${x.status==='paused'?'恢复':'停用'}</a><a class="position-delete danger-link">删除</a></td></tr>`).join('')||'<tr><td colspan="7" class="loading-cell">暂无岗位，请先新增</td></tr>'}</tbody></table><div class="list-footer"><span>共 ${positions.length} 条记录 · 当前第 1 页</span><label>每页 10 条</label></div></div>`;root.querySelector('#position-add').onclick=()=>openPositionForm(null,enterprises,plans);root.querySelector('#position-filter').onclick=()=>{const q=root.querySelector('#position-search').value.toLowerCase(),c=root.querySelector('#position-class').value;root.querySelectorAll('tbody tr').forEach(r=>r.style.display=r.textContent.toLowerCase().includes(q)&&(!c||r.textContent.includes(c))?'':'none');};root.querySelectorAll('.position-edit').forEach((a,i)=>a.onclick=()=>openPositionForm(positions[i],enterprises,plans));root.querySelectorAll('.position-delete').forEach((a,i)=>a.onclick=async()=>{if(confirm('确定删除该岗位？')){await api(`/positions/${positions[i].id}`,{method:'DELETE'});showToast('岗位已删除');renderPositions();}});root.querySelectorAll('.position-toggle').forEach(a=>a.onclick=()=>showToast('岗位状态已更新'));}catch(err){showToast(err.message);}}
function openPositionForm(item,enterprises,plans){const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box"><button class="modal-close">×</button><h2>${item?'编辑':'新增'}投保岗位</h2><form><label>投保单位<select name="enterprise_id" required>${enterprises.map(x=>`<option value="${x.id}">${esc(x.name)}</option>`).join('')}</select></label><label>实际用工单位<input name="actual_employer" value="${esc(item?.actual_employer||'')}" required></label><label>岗位名称<input name="name" value="${esc(item?.name||'')}" required></label><label>保险类别<select name="occupation_class"><option>1-3类</option><option>4类</option><option>5类</option><option>超5类</option></select></label><label>绑定产品方案<select name="plan_id"><option value="">暂不绑定</option>${plans.map(x=>`<option value="${x.id}">${esc(x.insurer)} · ${esc(x.name)}</option>`).join('')}</select></label><button class="primary full" type="submit">保存岗位</button><div class="auth-error"></div></form></div>`;document.body.appendChild(modal);if(item){modal.querySelector('[name="enterprise_id"]').value=item.enterprise_id;modal.querySelector('[name="occupation_class"]').value=item.occupation_class;modal.querySelector('[name="plan_id"]').value=item.plan_id||'';}modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async(e)=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));d.enterprise_id=Number(d.enterprise_id);d.plan_id=d.plan_id?Number(d.plan_id):null;try{await api(item?`/positions/${item.id}`:'/positions',{method:item?'PATCH':'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});modal.remove();showToast('岗位已保存');renderPositions();}catch(err){e.currentTarget.querySelector('.auth-error').textContent=err.message;}};}
function enhanceEnterpriseList(){const page=document.querySelector('#page-generic');const rows=document.querySelectorAll('#enterprise-rows tr');if(!page||!rows.length||rows[0].querySelector('.loading-cell'))return;if(!page.querySelector('[data-enterprise-search]')){const bar=document.createElement('div');bar.className='filterbar';bar.dataset.enterpriseSearch='1';bar.innerHTML='<input placeholder="搜索单位名称、联系人或手机号"><button class="outline">搜索</button><button class="outline">重置</button>';page.querySelector('.table-panel').before(bar);const input=bar.querySelector('input');const filter=()=>{const q=input.value.trim().toLowerCase();document.querySelectorAll('#enterprise-rows tr').forEach(row=>row.style.display=row.textContent.toLowerCase().includes(q)?'':'none');};bar.querySelector('button').onclick=filter;bar.querySelectorAll('button')[1].onclick=()=>{input.value='';filter();};}rows.forEach((row)=>{const cell=row.lastElementChild;if(cell&&!cell.querySelector('[data-enterprise-products]')){const a=document.createElement('a');a.href='#';a.dataset.enterpriseProducts='1';a.textContent='参保产品';cell.appendChild(a);}});}
document.addEventListener('click',(e)=>{if(e.target.closest('[data-page="team"]'))setTimeout(enhanceEnterpriseList,500);const a=e.target.closest('[data-enterprise-products]');if(a){e.preventDefault();const name=a.closest('tr')?.querySelector('b')?.textContent;api('/enterprises').then(items=>{const item=items.find(x=>x.name===name);if(item)openEnterpriseProducts(item);});}},true);
async function openEnterpriseProducts(item){try{const rows=await api(`/enterprises/${item.id}/products`);const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box detail-box" style="max-width:720px"><button class="modal-close">×</button><h2>参保产品 · ${esc(item.name)}</h2><p>该单位绑定的产品、业务员、佣金和保费统计</p><div class="detail-content">${rows.length?`<table class="mini-table"><thead><tr><th>产品方案</th><th>业务员</th><th>佣金比例</th><th>参保人数</th><th>保费总额</th><th>状态</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.insurer)} · ${esc(x.product)}</td><td>${esc(x.agent||'未分配')}</td><td>${Number(x.commission_rate)*100}%</td><td>${x.insured_count}</td><td>¥ ${Number(x.premium_total).toFixed(2)}</td><td>${esc(x.status)}</td></tr>`).join('')}</tbody></table>`:'<p>该单位暂未绑定参保产品。</p>'}</div><button class="primary full modal-close-action">关闭</button></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('.modal-close-action').onclick=()=>modal.remove();}catch(err){showToast(err.message);}}
async function renderEnterprises(){const root=document.querySelector('#page-generic');root.innerHTML='<div class="page-heading"><div><div class="kicker">ENTERPRISE MANAGEMENT</div><h1 id="generic-title">投保单位管理</h1><p>企业 / HR 机构、参保人数、双账户和单位管理员</p></div><button class="primary" id="enterprise-add">＋ 新增投保单位</button></div><div class="module-stats"><div><span>投保单位</span><b id="enterprise-total">0</b></div><div><span>参保人数</span><b>0</b></div><div><span>余额预警</span><b class="up">0</b></div></div><div class="panel table-panel"><div class="table-caption"><b>投保单位列表 <small id="enterprise-count">加载中</small></b><span>支持编辑、删除、充值和管理员</span></div><table><thead><tr><th>单位名称</th><th>类型</th><th>联系人</th><th>参保人数</th><th>保费账户</th><th>使用费账户</th><th>状态</th><th>操作</th></tr></thead><tbody id="enterprise-rows"><tr><td colspan="8" class="loading-cell">正在加载…</td></tr></tbody></table><div class="list-footer"><span id="enterprise-pagination">共 0 条记录 · 当前第 1 页</span><label>每页 10 条</label></div></div>';root.querySelector('#enterprise-add').onclick=()=>openEnterpriseForm();try{const items=await api('/enterprises');root.querySelector('#enterprise-total').textContent=items.length;root.querySelector('#enterprise-count').textContent=`共 ${items.length} 条记录`;root.querySelector('#enterprise-pagination').textContent=`共 ${items.length} 条记录 · 当前第 1 页`;root.querySelector('#enterprise-rows').innerHTML=items.map(x=>`<tr><td><b>${esc(x.name)}</b></td><td>${esc(x.kind)}</td><td>${esc(x.contact||'—')}</td><td>—</td><td>¥ ${Number(x.premium_balance).toFixed(2)}</td><td>¥ ${Number(x.usage_balance).toFixed(2)}</td><td><label class="status ${x.status==='approved'?'on':'wait'}">● ${x.status==='approved'?'已核验':'待核验'}</label></td><td><a data-enterprise-action="edit">编辑</a><a data-enterprise-action="recharge">充值</a><a data-enterprise-action="admins">管理员</a><a data-enterprise-action="delete" class="danger-link">删除</a></td></tr>`).join('')||'<tr><td colspan="8" class="loading-cell">暂无投保单位，请先新增</td></tr>';root.querySelectorAll('[data-enterprise-action]').forEach(a=>a.onclick=()=>{const name=a.closest('tr').querySelector('b').textContent;if(a.dataset.enterpriseAction==='delete')showToast('无数据可删除，新增单位后可执行删除');else if(a.dataset.enterpriseAction==='recharge')detail('账户充值',`<p>单位：${esc(name)}</p><p>选择保费账户或使用费账户并提交充值金额。</p>`);else if(a.dataset.enterpriseAction==='admins')detail('账号管理员',`<p>单位：${esc(name)}</p><p>支持新增、停用和重置单位管理员账号。</p>`);else showToast(`已打开 ${name} 编辑`);});}catch(err){showToast(err.message);}}

async function openRechargeForm(item){const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box"><button class="modal-close">×</button><h2>账户充值</h2><p>${esc(item.name)}</p><form><label>充值账户<select name="account"><option value="premium">保费核验账户</option><option value="usage">平台使用费账户</option></select></label><label>充值金额<input name="amount" type="number" min="0.01" step="0.01" required placeholder="请输入金额"></label><button class="primary full" type="submit">确认充值</button><div class="auth-error"></div></form></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async(e)=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));d.amount=Number(d.amount);try{await api(`/enterprises/${item.id}/recharge`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});modal.remove();showToast('充值成功，账户余额已更新');renderEnterprises();}catch(err){e.currentTarget.querySelector('.auth-error').textContent=err.message;}};}
async function openAdminForm(item){let admins=[];try{admins=await api(`/enterprises/${item.id}/admins`);}catch(err){showToast(err.message);return;}const list=admins.length?admins.map(a=>`<p>${esc(a.name)} · ${esc(a.username)} · ${a.active?'正常':'已停用'}</p>`).join(''):'<p>暂无管理员</p>';const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box"><button class="modal-close">×</button><h2>账号管理员</h2><p>${esc(item.name)}</p><div class="detail-content">${list}</div><button class="outline full" id="new-admin">＋ 新增管理员</button></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('#new-admin').onclick=()=>{modal.remove();openAdminCreate(item);};}
function openAdminCreate(item){const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box"><button class="modal-close">×</button><h2>新增单位管理员</h2><p>${esc(item.name)}</p><form><label>姓名<input name="name" required></label><label>登录账号<input name="username" required></label><label>初始密码<input name="password" value="123456" required></label><label>手机号<input name="phone"></label><button class="primary full" type="submit">创建管理员</button><div class="auth-error"></div></form></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async(e)=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));d.commission_rate=.15;try{await api(`/enterprises/${item.id}/admins`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});modal.remove();showToast('单位管理员已创建');}catch(err){e.currentTarget.querySelector('.auth-error').textContent=err.message;}};}
document.addEventListener('click',async(e)=>{const action=e.target.closest('[data-enterprise-action]');if(!action)return;const row=action.closest('tr');const name=row?.querySelector('b')?.textContent;if(!name)return;try{const items=await api('/enterprises');const item=items.find(x=>x.name===name);if(!item)return;if(action.dataset.enterpriseAction==='edit')openEnterpriseForm(item);if(action.dataset.enterpriseAction==='recharge')openRechargeForm(item);if(action.dataset.enterpriseAction==='admins')openAdminForm(item);if(action.dataset.enterpriseAction==='delete'){if(!confirm(`确定删除投保单位“${name}”？`))return;await api(`/enterprises/${item.id}`,{method:'DELETE'});showToast('投保单位已删除');renderEnterprises();}}catch(err){showToast(`操作失败：${err.message}`);}});
function openEnterpriseEdit(item){const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box"><button class="modal-close">×</button><h2>编辑投保单位</h2><form><label>单位名称<input name="name" required value="${esc(item.name)}"></label><label>单位类型<select name="kind"><option ${item.kind==='企业'?'selected':''}>企业</option><option ${item.kind==='HR机构'?'selected':''}>HR机构</option></select></label><label>统一社会信用代码<input name="credit_code" value="${esc(item.credit_code||'')}"></label><label>联系人<input name="contact" required value="${esc(item.contact||'')}"></label><label>联系电话<input name="phone" required value="${esc(item.phone||'')}"></label><button class="primary full" type="submit">保存修改</button><div class="auth-error"></div></form></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async(e)=>{e.preventDefault();try{const saved=await api(`/enterprises/${item.id}`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify(Object.fromEntries(new FormData(e.currentTarget)))});modal.remove();showToast(`单位“${saved.name}”已修改`);renderEnterprises();}catch(err){e.currentTarget.querySelector('.auth-error').textContent=err.message;}};}
document.addEventListener('click',async(e)=>{const action=e.target.closest('[data-enterprise-action]');if(!action)return;e.stopImmediatePropagation();const row=action.closest('tr');const name=row?.querySelector('b')?.textContent;try{const items=await api('/enterprises');const item=items.find(x=>x.name===name);if(!item)return;const kind=action.dataset.enterpriseAction;if(kind==='edit')openEnterpriseEdit(item);else if(kind==='recharge')openRechargeForm(item);else if(kind==='admins')openAdminForm(item);else if(kind==='delete'){if(!confirm(`确定删除投保单位“${name}”？`))return;await api(`/enterprises/${item.id}`,{method:'DELETE'});showToast('投保单位已删除');renderEnterprises();}}catch(err){showToast(`操作失败：${err.message}`);}},true);
function openEnterpriseForm(){const modal=document.createElement('div');modal.className='modal show';modal.innerHTML='<div class="modal-box"><button class="modal-close">×</button><h2>新增投保单位</h2><p>提交后单位进入待人工核验状态</p><form class="enterprise-form"><label>单位名称<input name="name" required placeholder="请输入企业或 HR 机构名称"></label><label>单位类型<select name="kind"><option>企业</option><option>HR机构</option></select></label><label>统一社会信用代码<input name="credit_code" placeholder="请输入统一社会信用代码"></label><label>联系人<input name="contact" required placeholder="请输入联系人"></label><label>联系电话<input name="phone" required placeholder="请输入联系电话"></label><button class="primary full" type="submit">提交投保单位</button><div class="auth-error"></div></form></div>';document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async(e)=>{e.preventDefault();const form=e.currentTarget,btn=form.querySelector('button[type="submit"]');btn.disabled=true;btn.textContent='提交中…';const data=Object.fromEntries(new FormData(form));try{const saved=await api('/enterprises',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});modal.remove();showToast(`投保单位“${saved.name}”已创建，等待人工核验`);renderEnterprises();}catch(err){form.querySelector('.auth-error').textContent=err.message;btn.disabled=false;btn.textContent='提交投保单位';}};}
// 投保单位唯一业务员：新增业务时根据单位自动带出并锁定业务员
async function openNewBusinessForm(){try{const [enterprises,plans,agents]=await Promise.all([api('/enterprises'),api('/plans'),api('/agents')]);const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box"><button class="modal-close">×</button><h2>新增业务</h2><p>选择投保单位后自动关联该单位业务员</p><form><label>投保单位<select name="enterprise_id" required>${enterprises.map(x=>`<option value="${x.id}">${esc(x.name)}</option>`).join('')}</select></label><label>关联业务员<input name="agent_display" readonly placeholder="选择投保单位后自动显示"><input type="hidden" name="agent_id"></label><label>产品方案<select name="plan_id" required>${plans.map(x=>`<option value="${x.id}">${esc(x.insurer)} · ${esc(x.name)}</option>`).join('')}</select></label><label>收益方式<select name="mode"><option value="rebate">返佣（按保司返佣比例）</option><option value="markup">加价（原始价上增加价）</option></select></label><label>返佣比例<input name="rate" type="number" min="0" max="1" step="0.01" value="0.15"></label><label>加价金额（元/人/月）<input name="markup_amount" type="number" min="0" step="0.01" value="0"></label><button class="primary full" type="submit">保存新增业务</button><div class="auth-error"></div></form></div>`;document.body.appendChild(modal);const form=modal.querySelector('form'),enterpriseSelect=form.querySelector('[name="enterprise_id"]');const syncAgent=()=>{const ent=enterprises.find(x=>String(x.id)===enterpriseSelect.value),agent=agents.find(x=>String(x.id)===String(ent?.agent_id));form.querySelector('[name="agent_id"]').value=agent?.id||'';form.querySelector('[name="agent_display"]').value=agent?`${agent.name}（自动关联）`:(ent?.agent_name&&ent.agent_name!=='未分配'?`${ent.agent_name}（自动关联）`:'该单位尚未关联业务员');};enterpriseSelect.addEventListener('change',syncAgent);syncAgent();modal.querySelector('.modal-close').onclick=()=>modal.remove();form.onsubmit=async(e)=>{e.preventDefault();const d=Object.fromEntries(new FormData(form));d.agent_id=Number(d.agent_id);d.enterprise_id=Number(d.enterprise_id);d.plan_id=Number(d.plan_id);d.rate=Number(d.rate);d.markup_amount=Number(d.markup_amount);if(!d.agent_id){form.querySelector('.auth-error').textContent='该投保单位尚未关联业务员，请先在投保单位管理中设置';return;}if(d.mode==='markup')d.rate=0;try{await api('/agent-commissions',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});modal.remove();showToast('新增业务已保存，业务员已自动关联');if(location.hash.includes('promotion'))renderPromotion();}catch(err){form.querySelector('.auth-error').textContent=err.message;}};}catch(err){showToast(`无法打开新增业务：${err.message}`);}}

// 佣金关系列表增加删除按钮
const commissionDeleteObserver=new MutationObserver(()=>{document.querySelectorAll('#commission-rows tr').forEach((row,i)=>{const cell=row.lastElementChild;if(!cell||cell.querySelector('[data-commission-delete]')||row.querySelector('.loading-cell'))return;const link=document.createElement('a');link.href='#';link.textContent='删除';link.dataset.commissionDelete='1';link.dataset.commissionIndex=String(i);link.style.marginLeft='10px';cell.appendChild(link);});});
commissionDeleteObserver.observe(document.body,{childList:true,subtree:true});
document.addEventListener('click',async(e)=>{const a=e.target.closest('[data-commission-delete]');if(!a)return;e.preventDefault();if(!confirm('确定删除这条业务佣金关联吗？'))return;try{const rows=await api('/agent-commissions');const item=rows[Number(a.dataset.commissionIndex)];if(!item)return;await api(`/agent-commissions/${item.id}`,{method:'DELETE'});showToast('业务佣金关联已删除');renderPromotion();}catch(err){showToast(`删除失败：${err.message}`);}},true);
// 报表中心与资金/发票中心使用真实接口
async function renderGeneric(page){
  if(page==='agents'){renderAgents();return;}
  if(page==='report'){return renderReports();}
  if(page==='billing'){return renderBilling();}
  const data=moduleData[page];const root=document.querySelector('#page-generic');if(!data)return;
  root.innerHTML=`<div class="page-heading"><div><div class="kicker">${data.k}</div><h1 id="generic-title">${pages[page]}</h1><p>${data.desc}</p></div><button class="primary generic-add">＋ 新增</button></div><div class="panel table-panel"><div class="table-caption"><b>${pages[page]}</b></div><table><thead><tr>${data.cols.map(c=>`<th>${c}</th>`).join('')}<th>操作</th></tr></thead><tbody>${data.rows.map(row=>`<tr>${row.map(c=>`<td>${c}</td>`).join('')}<td><a class="generic-view">查看</a><a class="generic-edit">编辑</a></td></tr>`).join('')}</tbody></table></div>`;
  root.querySelector('.generic-add')?.addEventListener('click',()=>detail(`新增${pages[page]}`,'<p>新增流程已准备就绪。</p>'));root.querySelectorAll('.generic-view').forEach(a=>a.onclick=()=>showToast('详情已打开'));root.querySelectorAll('.generic-edit').forEach(a=>a.onclick=()=>showToast('编辑流程已打开'));
}
async function renderReports(){const root=document.querySelector('#page-generic');try{const rows=await api('/reports');root.innerHTML=`<div class="page-heading"><div><div class="kicker">REPORT CENTER</div><h1>报表中心</h1><p>保费、参保人员与理赔经营数据</p></div><button class="primary" id="report-export">导出报表</button></div><div class="module-stats">${rows.map(x=>`<div><span>${esc(x.name)}</span><b>${x.id==='premium'?'¥ '+Number(x.value).toFixed(2):x.value}</b></div>`).join('')}</div><div class="panel table-panel"><div class="table-caption"><b>报表列表 <small>共 ${rows.length} 条</small></b></div><table><thead><tr><th>报表名称</th><th>统计周期</th><th>指标值</th><th>说明</th><th>操作</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.name)}</td><td>${x.period}</td><td>${x.id==='premium'?'¥ '+Number(x.value).toFixed(2):x.value}</td><td>${esc(x.detail)}</td><td><a data-report-view="${x.id}">查看</a><a data-report-export="${x.id}">导出</a></td></tr>`).join('')}</tbody></table></div>`;root.querySelector('#report-export').onclick=()=>exportGeneric({cols:['报表','周期','指标值','说明'],rows:rows.map(x=>[x.name,x.period,x.value,x.detail])});root.querySelectorAll('[data-report-view]').forEach(a=>a.onclick=()=>showToast('报表明细已加载'));root.querySelectorAll('[data-report-export]').forEach(a=>a.onclick=()=>root.querySelector('#report-export').click());}catch(err){showToast(err.message);}}
async function renderBilling(){const root=document.querySelector('#page-generic');try{const rows=await api('/billing');root.innerHTML=`<div class="page-heading"><div><div class="kicker">FUND & INVOICE</div><h1>资金与发票</h1><p>账户余额、充值和发票申请</p></div><button class="primary" id="billing-recharge">＋ 账户充值</button></div><div class="panel table-panel"><div class="table-caption"><b>账户列表 <small>共 ${rows.length} 条</small></b></div><table><thead><tr><th>投保单位</th><th>账户类型</th><th>余额</th><th>状态</th><th>操作</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.enterprise_name)}</td><td>${x.account}</td><td>¥ ${Number(x.balance).toFixed(2)}</td><td>${x.status}</td><td><a data-billing-recharge="${x.id}" data-account="${x.account==='保费账户'?'premium':'usage'}">充值</a><a data-billing-invoice="${x.id}">申请发票</a></td></tr>`).join('')||'<tr><td colspan="5">暂无账户数据</td></tr>'}</tbody></table></div>`;const recharge=async(id,account)=>{const amount=prompt('请输入充值金额');if(!amount||Number(amount)<=0)return;try{await api(`/enterprises/${id}/recharge`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({account,amount:Number(amount)})});showToast('充值成功');renderBilling();}catch(err){showToast(err.message);}};root.querySelectorAll('[data-billing-recharge]').forEach(a=>a.onclick=()=>recharge(a.dataset.billingRecharge,a.dataset.account));root.querySelectorAll('[data-billing-invoice]').forEach(a=>a.onclick=()=>showToast('发票申请已提交，平台审核后开具'));root.querySelector('#billing-recharge').onclick=()=>{const first=root.querySelector('[data-billing-recharge]');if(first)recharge(first.dataset.billingRecharge,first.dataset.account);};}catch(err){showToast(err.message);}}
async function renderBilling(){const root=document.querySelector('#page-generic');try{const rows=await api('/billing');const units=[...new Map(rows.map(x=>[x.id,x])).values()];root.innerHTML=`<div class="page-heading"><div><div class="kicker">FUND & INVOICE</div><h1>资金与发票</h1><p>保费账户与平台使用费账户分开管理</p></div><button class="primary" id="billing-recharge">＋ 账户充值</button></div><div class="panel table-panel"><div class="table-caption"><b>账户余额与费用规则</b></div><table><thead><tr><th>投保单位</th><th>账户类型</th><th>账户余额</th><th>每日使用费单价</th><th>预计日扣费</th><th>操作</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.enterprise_name)}</td><td>${x.account}</td><td>¥ ${Number(x.balance).toFixed(2)}</td><td>${x.account==='平台使用费账户'?'¥ '+Number(x.daily_rate||0.1).toFixed(2)+' / 人 / 天':'—'}</td><td>${x.account==='平台使用费账户'?'¥ '+Number(x.estimated_daily||0).toFixed(2):'—'}</td><td><a data-billing-recharge="${x.id}" data-account="${x.account==='保费账户'?'premium':'usage'}">充值</a>${x.account==='平台使用费账户'?`<a data-usage-setting="${x.id}">设置单价</a>`:''}<a data-billing-invoice="${x.id}">申请发票</a></td></tr>`).join('')||'<tr><td colspan="6">暂无账户数据</td></tr>'}</tbody></table></div>`;const recharge=async(id,account)=>{const amount=prompt(account==='premium'?'请输入保费充值金额':'请输入平台使用费充值金额');if(!amount||Number(amount)<=0)return;try{await api(`/enterprises/${id}/recharge`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({account,amount:Number(amount)})});showToast('充值成功');renderBilling();}catch(err){showToast(err.message);}};root.querySelectorAll('[data-billing-recharge]').forEach(a=>a.onclick=()=>recharge(a.dataset.billingRecharge,a.dataset.account));root.querySelectorAll('[data-usage-setting]').forEach(a=>a.onclick=async()=>{const rate=prompt('设置平台使用费（元/人/天）', '0.1');if(rate===null||Number(rate)<0)return;try{await api(`/enterprises/${a.dataset.usageSetting}`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({usage_fee_daily:Number(rate)})});showToast('平台使用费单价已更新');renderBilling();}catch(err){showToast(err.message);}});root.querySelectorAll('[data-billing-invoice]').forEach(a=>a.onclick=()=>showToast('发票申请已提交'));root.querySelector('#billing-recharge').onclick=()=>{const a=root.querySelector('[data-billing-recharge]');if(a)recharge(a.dataset.billingRecharge,a.dataset.account);};}catch(err){showToast(err.message);}}
// 产品方案计费及生效模式字段
(()=>{const form=document.querySelector('#plan-form');if(form&&!form.querySelector('[name="billing_mode"]')){const anchor=form.querySelector('[name="payment_mode"]')?.closest('label');['billing_mode','effective_mode'].forEach((name)=>{const label=document.createElement('label');label.textContent=name==='billing_mode'?'计费模式':'保险生效时间';label.innerHTML+=name==='billing_mode'?'<select name="billing_mode"><option value="monthly">按月计费</option><option value="daily">按天计费</option></select>':'<select name="effective_mode"><option value="next_day">次日生效</option><option value="immediate">即时生效</option></select>';anchor?.after(label);});}const h=document.querySelector('.plan-table thead tr');if(h&&!h.querySelector('[data-billing-head]')){const a=document.createElement('th');a.dataset.billingHead='1';a.textContent='计费模式';const b=document.createElement('th');b.textContent='生效时间';h.querySelector('th:nth-last-child(2)')?.before(a,b);}})();
async function renderEnrollmentCenter(){const root=document.querySelector('#page-generic');try{const [enterprises,plans]=await Promise.all([api('/enterprises'),api('/plans')]);const ent=enterprises[0],plan=plans[0];root.innerHTML=`<div class="page-heading"><div><div class="kicker">ENROLLMENT CENTER</div><h1>参停保中心</h1><p>真实发送参保/停保名单，并跟踪保司回执</p></div><button class="primary" id="batch-create">＋ 生成发送批次</button></div><div class="panel table-panel"><div class="table-caption"><b>参停保发送记录</b><span>${ent?esc(ent.name):'暂无投保单位'}</span></div><table><thead><tr><th>投保单位</th><th>产品方案</th><th>类型</th><th>操作</th></tr></thead><tbody>${ent&&plan?`<tr><td>${esc(ent.name)}</td><td>${esc(plan.name)}</td><td>参保 / 停保</td><td><a data-enroll-send="enrollment">发送参保</a><a data-enroll-send="termination">发送停保</a><a data-email-list="1">邮件名单</a><a data-sms-notify="1">短信通知</a></td></tr>`:'<tr><td colspan="4">请先配置投保单位和平台产品方案</td></tr>'}</tbody></table></div>`;root.querySelector('#batch-create').onclick=()=>showToast('发送批次已生成，可选择参保或停保发送');root.querySelectorAll('[data-enroll-send]').forEach(a=>a.onclick=async()=>{try{const r=await api(`/enrollment/send?enterprise_id=${ent.id}&plan_id=${plan.id}&kind=${a.dataset.enrollSend}`,{method:'POST'});showToast(`${r.kind==='enrollment'?'参保':'停保'}名单已发送，回执号：${r.request_id}`);}catch(err){showToast(`发送失败：${err.message}`);}});root.querySelector('[data-email-list]')?.addEventListener('click',async()=>{try{const r=await api('/notifications/send',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({kind:'email',recipient:ent.contact||'',subject:'参停保名单',content:`${ent.name}参停保名单已生成，请查收`})});showToast(r.message);}catch(err){showToast(err.message);}});root.querySelector('[data-sms-notify]')?.addEventListener('click',async()=>{try{const r=await api('/notifications/send',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({kind:'sms',recipient:ent.phone||'',content:`${ent.name}参停保名单已发送`})});showToast(r.message);}catch(err){showToast(err.message);}});}catch(err){showToast(err.message);}}
async function renderDataScreen(){const root=document.querySelector('#page-screen');try{const [rows,dash]=await Promise.all([api('/screen/products'),api('/dashboard')]);const people=rows.reduce((n,x)=>n+x.insured_count,0),units=rows.reduce((n,x)=>n+x.enterprise_count,0),premium=rows.reduce((n,x)=>n+x.premium_total,0),alerts=dash.balance_alerts||[];root.innerHTML=`<div class="page-heading"><div><div class="kicker">OPERATING DATA SCREEN</div><h1>经营数据大屏</h1><p>产品经营数据与账户余额风险实时监控</p></div><span class="screen-time">● 实时数据</span></div><div class="screen-cards"><div><span>参保员工</span><b>${people}</b><em>产品汇总</em></div><div><span>参保单位</span><b>${units}</b><em>去重单位数</em></div><div><span>累计保费</span><b>¥ ${premium.toFixed(2)}</b><em>保单汇总</em></div><div><span>余额预警</span><b class="${alerts.length?'danger-text':''}">${alerts.length}</b><em>提前 3-7 天提醒</em></div></div><div class="panel table-panel"><div class="table-caption"><b>重要提醒</b><span>按当前规模估算</span></div>${alerts.length?`<table><thead><tr><th>投保单位</th><th>账户</th><th>当前余额</th><th>预计日消耗</th><th>预计剩余</th><th>提醒阈值</th></tr></thead><tbody>${alerts.map(x=>`<tr><td>${esc(x.enterprise_name)}</td><td>${x.account==='premium'?'保费账户':'平台使用费账户'}</td><td>¥ ${Number(x.balance).toFixed(2)}</td><td>¥ ${Number(x.daily_burn).toFixed(2)}</td><td class="danger-text">${x.days_left} 天</td><td>${x.alert_days} 天</td></tr>`).join('')}</tbody></table>`:'<div class="empty-state">暂无余额告罄风险，当前账户余额充足。</div>'}</div><div class="panel table-panel"><div class="table-caption"><b>产品经营明细 <small>共 ${rows.length} 条</small></b></div><table><thead><tr><th>保险公司</th><th>产品方案</th><th>在保人数</th><th>参保单位数量</th><th>保单数</th><th>累计保费</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.insurer)}</td><td>${esc(x.product)}</td><td>${x.insured_count}</td><td>${x.enterprise_count}</td><td>${x.policy_count}</td><td>¥ ${Number(x.premium_total).toFixed(2)}</td></tr>`).join('')||'<tr><td colspan="6">暂无数据</td></tr>'}</tbody></table></div>`;}catch(err){showToast(err.message);}}
const balanceAlertSettingObserver=new MutationObserver(()=>{document.querySelectorAll('#page-generic tbody tr').forEach(row=>{const account=row.children[1]?.textContent;if(account!=='保费账户'||row.querySelector('[data-alert-setting]'))return;const id=row.querySelector('[data-billing-recharge]')?.dataset.billingRecharge;if(!id)return;const a=document.createElement('a');a.href='#';a.textContent='设置预警天数';a.dataset.alertSetting=id;a.style.marginLeft='10px';row.lastElementChild.appendChild(a);});});balanceAlertSettingObserver.observe(document.body,{childList:true,subtree:true});document.addEventListener('click',async e=>{const a=e.target.closest('[data-alert-setting]');if(!a)return;e.preventDefault();const days=prompt('余额告罄提前提醒天数（3-7）','3');if(days===null||Number(days)<3||Number(days)>7){showToast('请输入 3-7 天');return;}try{await api(`/enterprises/${a.dataset.alertSetting}`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({alert_days:Number(days)})});showToast('余额预警参数已更新');renderBilling();}catch(err){showToast(err.message);}},true);
(()=>{const m=document.querySelector('#modal');if(m&&!m.querySelector('[name="id_number"]')){const l=document.createElement('label');l.innerHTML='身份证号<input name="id_number" required placeholder="请输入18位身份证号">';m.querySelector('[name="personName"]')?.closest('label')?.after(l);}})();
async function renderEnrollmentCenter(){const root=document.querySelector('#page-generic');try{const [enterprises,plans]=await Promise.all([api('/enterprises'),api('/plans')]);root.innerHTML=`<div class="page-heading"><div><div class="kicker">ENROLLMENT CENTER</div><h1>参停保中心</h1><p>按保险产品和日期导出当日新参保、停保名单</p></div></div><div class="filterbar"><select id="export-plan"><option value="">全部保险产品</option>${plans.map(p=>`<option value="${p.id}">${esc(p.insurer)} · ${esc(p.name)}</option>`).join('')}</select><input id="export-date" type="date" value="${new Date().toISOString().slice(0,10)}"><button class="primary" id="export-enrollment">导出当日新参保</button><button class="outline" id="export-termination">导出当日停保</button></div><div class="panel table-panel"><div class="table-caption"><b>名单导出</b><span>单位：${esc(enterprises[0]?.name||'全部单位')}</span></div><div class="empty-state">选择保险产品和日期后导出 CSV 名单，包含实际用工单位、岗位、身份证号、职业类别和状态。</div></div>`;const download=async kind=>{const q=new URLSearchParams({kind,date:root.querySelector('#export-date').value});const plan=root.querySelector('#export-plan').value;if(plan)q.set('plan_id',plan);try{const res=await fetch(`${API}/enrollment/export?${q}`,{headers:{Authorization:`Bearer ${authToken()}`}});if(!res.ok)throw new Error('导出失败');const blob=await res.blob(),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`${kind}-${q.get('date')}.csv`;a.click();URL.revokeObjectURL(a.href);showToast('名单已导出');}catch(err){showToast(err.message);}};root.querySelector('#export-enrollment').onclick=()=>download('enrollment');root.querySelector('#export-termination').onclick=()=>download('termination');}catch(err){showToast(err.message);}}
async function renderEnrollmentCenter(){const root=document.querySelector('#page-generic');try{const [plans,people,enterprises]=await Promise.all([api('/plans'),api('/insured'),api('/enterprises')]);const today=new Date().toISOString().slice(0,10);const rows=plans.map(p=>{const ps=people.filter(x=>x.policy_id===p.id||x.plan_id===p.id);const fresh=people.filter(x=>String(x.created_at||'').slice(0,10)===today&&x.status!=='stopped').length;const stopped=people.filter(x=>String(x.created_at||'').slice(0,10)===today&&x.status==='stopped').length;return {...p,insured:ps.length,new_count:fresh,stop_count:stopped,enterprise:enterprises[0]};});root.innerHTML=`<div class="page-heading"><div><div class="kicker">ENROLLMENT CENTER</div><h1>参停保中心</h1><p>按保险公司和产品查看在保、今日新参和今日停保数据</p></div><input id="enroll-date" type="date" value="${today}"></div><div class="panel table-panel"><div class="table-caption"><b>保险产品参停保列表 <small>共 ${rows.length} 条记录</small></b><span>名单可导出或直接邮件发送</span></div><table><thead><tr><th>保险公司</th><th>产品</th><th>在保人数</th><th>今日新参人数</th><th>今日停保人数</th><th>操作</th></tr></thead><tbody>${rows.map((x,i)=>`<tr><td>${esc(x.insurer)}<small class="muted">${esc(x.insurer_email||'未配置邮箱')}</small></td><td>${esc(x.name)}</td><td>${x.insured}</td><td>${x.new_count}</td><td>${x.stop_count}</td><td><a data-export-kind="enrollment" data-plan="${x.id}">导出新参</a><a data-export-kind="termination" data-plan="${x.id}">导出停保</a><a data-email-kind="enrollment" data-plan="${x.id}">邮件新参</a><a data-email-kind="termination" data-plan="${x.id}">邮件停保</a></td></tr>`).join('')||'<tr><td colspan="6">暂无产品数据</td></tr>'}</tbody></table></div>`;const download=async(plan,kind)=>{const d=root.querySelector('#enroll-date').value,res=await fetch(`${API}/enrollment/export?kind=${kind}&date=${d}&plan_id=${plan}`,{headers:{Authorization:`Bearer ${authToken()}`}});if(!res.ok)throw new Error('导出失败');const blob=await res.blob(),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`${kind}-${d}.csv`;a.click();URL.revokeObjectURL(a.href);showToast('名单已导出');};root.querySelectorAll('[data-export-kind]').forEach(a=>a.onclick=()=>download(a.dataset.plan,a.dataset.exportKind).catch(e=>showToast(e.message)));root.querySelectorAll('[data-email-kind]').forEach(a=>a.onclick=async()=>{try{const r=await api(`/enrollment/email?enterprise_id=${a.dataset.enterprise||enterprises[0]?.id||1}&plan_id=${a.dataset.plan}&kind=${a.dataset.emailKind}`,{method:'POST'});showToast(`邮件已发送：${r.email}`);}catch(e){showToast(e.message);}});}catch(err){showToast(err.message);}}
async function renderEnrollmentCenter(){const root=document.querySelector('#page-generic');try{const [rows,enterprises]=await Promise.all([api('/enrollment/summary'),api('/enterprises')]);const today=new Date().toISOString().slice(0,10);root.innerHTML=`<div class="page-heading"><div><div class="kicker">ENROLLMENT CENTER</div><h1>参停保中心</h1><p>保险公司、产品、在保人数和当日参停保名单</p></div><input id="enroll-date" type="date" value="${today}"></div><div class="panel table-panel"><div class="table-caption"><b>参停保产品列表 <small>共 ${rows.length} 条</small></b><span>支持导出和直接邮件发送</span></div><table><thead><tr><th>保险公司</th><th>产品</th><th>在保人数</th><th>今日新参人数</th><th>今日停保人数</th><th>操作</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.insurer)}<small class="muted">${esc(x.insurer_email||'未配置邮箱')}</small></td><td>${esc(x.product)}</td><td>${x.insured_count}</td><td>${x.new_count}</td><td>${x.stop_count}</td><td><a data-export-kind="enrollment" data-plan="${x.plan_id}">导出新参</a><a data-export-kind="termination" data-plan="${x.plan_id}">导出停保</a><a data-email-kind="enrollment" data-plan="${x.plan_id}">邮件新参</a><a data-email-kind="termination" data-plan="${x.plan_id}">邮件停保</a></td></tr>`).join('')||'<tr><td colspan="6">暂无产品数据</td></tr>'}</tbody></table></div>`;const download=async(plan,kind)=>{const d=root.querySelector('#enroll-date').value,res=await fetch(`${API}/enrollment/export?kind=${kind}&date=${d}&plan_id=${plan}`,{headers:{Authorization:`Bearer ${authToken()}`}});if(!res.ok)throw new Error('导出失败');const blob=await res.blob(),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`${kind}-${d}.csv`;a.click();URL.revokeObjectURL(a.href);showToast('名单已导出');};root.querySelectorAll('[data-export-kind]').forEach(a=>a.onclick=()=>download(a.dataset.plan,a.dataset.exportKind).catch(e=>showToast(e.message)));root.querySelectorAll('[data-email-kind]').forEach(a=>a.onclick=async()=>{try{const r=await api(`/enrollment/email?enterprise_id=${enterprises[0]?.id||1}&plan_id=${a.dataset.plan}&kind=${a.dataset.emailKind}`,{method:'POST'});showToast(r.message||`邮件已发送：${r.email}`);}catch(e){showToast(e.message);}});}catch(err){showToast(err.message);}}
(()=>{const f=document.querySelector('#plan-form');if(f&&!f.querySelector('[name="insurer_email"]')){const l=document.createElement('label');l.innerHTML='保险公司名单接收邮箱<input name="insurer_email" type="email" placeholder="claims@example.com">';f.querySelector('[name="insurer"]')?.closest('label')?.after(l);}})();
async function renderEnrollmentCenter(){const root=document.querySelector('#page-generic');try{const [summary,enterprises,positions]=await Promise.all([api('/enrollment/summary'),api('/enterprises'),api('/positions')]);const approved=positions.filter(x=>x.status==='approved'),today=new Date().toISOString().slice(0,10);root.innerHTML=`<div class="page-heading"><div><div class="kicker">ENROLLMENT CENTER</div><h1>参停保中心</h1><p>三端统一支持 CSV/XLSX 批量参保、批量停保</p></div></div><div class="panel plan-entry"><div class="panel-title"><div><h2>上传电子表格</h2><small>先校验全部数据，存在错误时整批不入库</small></div></div><form id="bulk-insured-form" class="form-grid"><label>业务类型<select name="kind"><option value="enrollment">批量参保</option><option value="termination">批量停保</option></select></label><label>投保单位<select name="enterprise_id">${enterprises.map(x=>`<option value="${x.id}">${esc(x.name)}</option>`).join('')}</select></label><label>审核岗位<select name="position_id"><option value="0">停保无需岗位</option>${approved.map(x=>`<option value="${x.id}" data-enterprise="${x.enterprise_id}">${esc(x.actual_employer_name||x.actual_employer)} · ${esc(x.name)}</option>`).join('')}</select></label><label class="wide">电子表格<input name="file" type="file" accept=".csv,.xlsx" required></label><div class="form-actions wide"><button class="primary" type="submit">上传并执行</button><a class="outline" id="bulk-template">下载导入模板</a></div><div class="auth-error wide"></div></form></div><div class="panel table-panel"><div class="table-caption"><b>产品参停保统计 <small>共 ${summary.length} 条</small></b><input id="enroll-date" type="date" value="${today}"></div><table><thead><tr><th>保险公司</th><th>产品</th><th>在保人数</th><th>今日新参</th><th>今日停保</th><th>操作</th></tr></thead><tbody>${summary.map(x=>`<tr><td>${esc(x.insurer)}<small class="muted">${esc(x.insurer_email||'未配置邮箱')}</small></td><td>${esc(x.product)}</td><td>${x.insured_count}</td><td>${x.new_count}</td><td>${x.stop_count}</td><td><a data-export-kind="enrollment" data-plan="${x.plan_id}">导出新参</a><a data-export-kind="termination" data-plan="${x.plan_id}">导出停保</a><a data-email-kind="enrollment" data-plan="${x.plan_id}">邮件新参</a><a data-email-kind="termination" data-plan="${x.plan_id}">邮件停保</a></td></tr>`).join('')||'<tr><td colspan="6">暂无产品数据</td></tr>'}</tbody></table></div>`;const form=root.querySelector('#bulk-insured-form'),kind=form.querySelector('[name="kind"]'),position=form.querySelector('[name="position_id"]');kind.onchange=()=>{position.disabled=kind.value==='termination';};form.onsubmit=async e=>{e.preventDefault();const error=form.querySelector('.auth-error'),btn=form.querySelector('button');error.textContent='';if(kind.value==='enrollment'&&Number(position.value)===0){error.textContent='批量参保必须选择审核通过的岗位';return;}btn.disabled=true;btn.textContent='上传校验中…';try{const fd=new FormData(form),res=await fetch(`${API}/insured/import-file`,{method:'POST',headers:{Authorization:`Bearer ${authToken()}`},body:fd}),data=await res.json();if(!res.ok)throw new Error(data.detail||'导入失败');if(!data.ok){error.innerHTML=data.errors.slice(0,20).map(x=>`第 ${x.row} 行：${esc(x.message)}`).join('<br>');return;}showToast(`${data.kind==='enrollment'?'参保':'停保'}成功 ${data.success} 人`);renderEnrollmentCenter();}catch(err){error.textContent=err.message;}finally{btn.disabled=false;btn.textContent='上传并执行';}};root.querySelector('#bulk-template').onclick=async()=>{const res=await fetch(`${API}/insured/import-template`,{headers:{Authorization:`Bearer ${authToken()}`}}),blob=await res.blob(),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='参保员工批量导入模板.csv';a.click();URL.revokeObjectURL(a.href);};const download=async(plan,k)=>{const d=root.querySelector('#enroll-date').value,res=await fetch(`${API}/enrollment/export?kind=${k}&date=${d}&plan_id=${plan}`,{headers:{Authorization:`Bearer ${authToken()}`}}),blob=await res.blob(),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`${k}-${d}.csv`;a.click();URL.revokeObjectURL(a.href);};root.querySelectorAll('[data-export-kind]').forEach(a=>a.onclick=()=>download(a.dataset.plan,a.dataset.exportKind));root.querySelectorAll('[data-email-kind]').forEach(a=>a.onclick=async()=>{try{const r=await api(`/enrollment/email?enterprise_id=${enterprises[0]?.id||1}&plan_id=${a.dataset.plan}&kind=${a.dataset.emailKind}`,{method:'POST'});showToast(r.message);}catch(err){showToast(err.message);}});}catch(err){showToast(err.message);}}
const claimStatusText={reported:'已报案',collecting:'材料收集中',submitted:'已提交保司',insurer_review:'保司审核中',supplement:'待补充材料',approved:'核赔通过',paid:'已赔付',rejected:'拒赔',closed:'已结案'};
async function renderClaims(){const root=document.querySelector('#page-generic');try{const rows=await api('/claims');root.innerHTML=`<div class="page-heading"><div><div class="kicker">WORK INJURY CLAIMS</div><h1>工伤理赔工作台</h1><p>报案、材料、保司审核、核赔、支付和结案全流程</p></div><button class="primary" id="claim-add">＋ 新增报案</button></div><div class="module-stats"><div><span>案件总数</span><b>${rows.length}</b></div><div><span>处理中</span><b>${rows.filter(x=>!['paid','rejected','closed'].includes(x.status)).length}</b></div><div><span>待补材料</span><b>${rows.filter(x=>x.status==='supplement'||x.missing_count>0).length}</b></div><div><span>申请金额</span><b>¥ ${rows.reduce((n,x)=>n+Number(x.amount||0),0).toFixed(2)}</b></div></div><div class="filterbar"><input id="claim-search" placeholder="搜索案件号、员工、单位"><select id="claim-status"><option value="">全部状态</option>${Object.entries(claimStatusText).map(([k,v])=>`<option value="${k}">${v}</option>`).join('')}</select><button class="outline" id="claim-filter">筛选</button></div><div class="panel table-panel"><div class="table-caption"><b>理赔案件 <small>共 ${rows.length} 条</small></b><span>材料和进度实时同步</span></div><table><thead><tr><th>案件号</th><th>员工 / 用工单位</th><th>事故信息</th><th>申请金额</th><th>材料</th><th>当前节点</th><th>负责人 / SLA</th><th>操作</th></tr></thead><tbody id="claim-rows">${rows.map(x=>`<tr><td><b>${esc(x.claim_no)}</b></td><td>${esc(x.person_name)}<small>${esc(x.actual_employer_name||x.enterprise_name)}</small></td><td>${esc(x.accident_type)}<small>${esc(x.accident_at)} · ${esc(x.accident_place)}</small></td><td>¥ ${Number(x.amount||0).toFixed(2)}</td><td>${x.document_count} 份<small class="${x.missing_count?'danger-text':''}">缺 ${x.missing_count} 项</small></td><td><label class="status ${['approved','paid','closed'].includes(x.status)?'on':x.status==='rejected'?'off':'wait'}">● ${claimStatusText[x.status]||x.status}</label></td><td>${esc(x.current_handler)}<small>${esc(x.deadline||'未设置')}</small></td><td><a data-claim-detail="${x.id}">案件工作台</a></td></tr>`).join('')||'<tr><td colspan="8" class="loading-cell">暂无理赔案件</td></tr>'}</tbody></table></div>`;root.querySelector('#claim-add').onclick=()=>openClaimCreate();root.querySelector('#claim-filter').onclick=()=>{const q=root.querySelector('#claim-search').value.toLowerCase(),s=root.querySelector('#claim-status').value;root.querySelectorAll('#claim-rows tr').forEach((tr,i)=>tr.style.display=tr.textContent.toLowerCase().includes(q)&&(!s||rows[i]?.status===s)?'':'none');};root.querySelectorAll('[data-claim-detail]').forEach(a=>a.onclick=()=>openClaimWorkbench(Number(a.dataset.claimDetail)));}catch(err){showToast(err.message);}}
async function openClaimCreate(){try{const [enterprises,people]=await Promise.all([api('/enterprises'),api('/insured')]);const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box detail-box"><button class="modal-close">×</button><h2>新增工伤报案</h2><p>事故发生后尽快登记，系统按事故日期计算30日单位申请提醒</p><form><label>投保单位<select name="enterprise_id">${enterprises.map(x=>`<option value="${x.id}">${esc(x.name)}</option>`).join('')}</select></label><label>受伤员工<select name="person_id">${people.map(x=>`<option value="${x.id}" data-enterprise="${x.enterprise_id}">${esc(x.name)} · ${esc(x.id_number)}</option>`).join('')}</select></label><label>事故时间<input type="datetime-local" name="accident_at" required></label><label>事故地点<input name="accident_place" required></label><label>事故类型<select name="accident_type"><option>工作场所事故</option><option>上下班交通事故</option><option>职业病</option><option>突发疾病</option><option>其他工伤事故</option></select></label><label>就诊医院<input name="hospital"></label><label>初步诊断<input name="diagnosis"></label><label>联系人<input name="contact_name"></label><label>联系电话<input name="contact_phone"></label><label>预计申请金额<input type="number" name="amount" min="0" step="0.01" value="0"></label><label class="wide">事故经过<textarea name="description" required></textarea></label><button class="primary full" type="submit">提交报案</button><div class="auth-error"></div></form></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const d=Object.fromEntries(new FormData(e.currentTarget));d.enterprise_id=Number(d.enterprise_id);d.person_id=Number(d.person_id);d.amount=Number(d.amount);try{await api('/claims',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});modal.remove();showToast('工伤报案已创建');renderClaims();}catch(err){e.currentTarget.querySelector('.auth-error').textContent=err.message;}};}catch(err){showToast(err.message);}}
async function openClaimWorkbench(id){try{const [rows,docs,timeline,checklist]=await Promise.all([api('/claims'),api(`/claims/${id}/documents`),api(`/claims/${id}/timeline`),api(`/claims/${id}/checklist`)]),item=rows.find(x=>x.id===id);if(!item)return;const modal=document.createElement('div');modal.className='modal show';modal.innerHTML=`<div class="modal-box detail-box" style="max-width:980px"><button class="modal-close">×</button><h2>${esc(item.claim_no)} · ${esc(item.person_name)}</h2><p>${esc(item.enterprise_name)} / ${esc(item.actual_employer_name)} / ${esc(item.position_name)}</p><div class="module-stats mini-product-stats"><div><span>当前节点</span><b>${claimStatusText[item.status]||item.status}</b></div><div><span>申请金额</span><b>¥ ${Number(item.amount).toFixed(2)}</b></div><div><span>核赔金额</span><b>¥ ${Number(item.approved_amount||0).toFixed(2)}</b></div><div><span>材料完整度</span><b>${checklist.filter(x=>x.uploaded).length}/${checklist.length}</b></div></div><div class="claim-work-grid"><div class="panel"><h3>案件信息</h3><p>事故：${esc(item.accident_at)} · ${esc(item.accident_place)}</p><p>类型：${esc(item.accident_type)}</p><p>医院：${esc(item.hospital||'—')}</p><p>诊断：${esc(item.diagnosis||'—')}</p><p>申请期限提醒：${esc(item.deadline||'—')}</p><form id="claim-status-form"><label>推进节点<select name="status">${Object.entries(claimStatusText).map(([k,v])=>`<option value="${k}">${v}</option>`).join('')}</select></label><label>处理意见<input name="note"></label><label>核赔金额<input name="approved_amount" type="number" min="0" step="0.01"></label><button class="primary" type="submit">更新进度</button><div class="auth-error"></div></form></div><div class="panel"><h3>材料清单</h3>${checklist.map(x=>`<p>${x.uploaded?'✅':'⬜'} ${esc(x.name)} ${x.required?'<small>必需</small>':''}</p>`).join('')}<form id="claim-upload-form"><label>材料类型<select name="doc_type">${checklist.map(x=>`<option value="${x.doc_type}">${esc(x.name)}</option>`).join('')}</select></label><label>选择文件<input type="file" name="file" accept="image/*,.pdf,.doc,.docx,.xls,.xlsx" required></label><button class="outline" type="submit">上传材料</button><div class="auth-error"></div></form>${docs.map(x=>`<p><a href="${esc(x.url)}" target="_blank">${esc(x.name)}</a></p>`).join('')}</div><div class="panel"><h3>处理时间线</h3>${timeline.map(x=>`<div class="timeline-item"><b>${claimStatusText[x.node]||esc(x.node)}</b><p>${esc(x.action)} ${x.note?'· '+esc(x.note):''}</p><small>${esc(x.operator)} · ${new Date(x.created_at).toLocaleString()}</small></div>`).join('')||'<p>暂无处理记录</p>'}</div></div></div>`;document.body.appendChild(modal);modal.querySelector('.modal-close').onclick=()=>modal.remove();const sf=modal.querySelector('#claim-status-form');sf.querySelector('[name="status"]').value=item.status;sf.onsubmit=async e=>{e.preventDefault();const d=Object.fromEntries(new FormData(sf));d.approved_amount=d.approved_amount?Number(d.approved_amount):null;try{await api(`/claims/${id}/status`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});modal.remove();showToast('理赔进度已更新');renderClaims();}catch(err){sf.querySelector('.auth-error').textContent=err.message;}};const uf=modal.querySelector('#claim-upload-form');uf.onsubmit=async e=>{e.preventDefault();const fd=new FormData(uf);try{const res=await fetch(`${API}/claims/${id}/documents/upload`,{method:'POST',headers:{Authorization:`Bearer ${authToken()}`},body:fd}),data=await res.json();if(!res.ok)throw new Error(data.detail||'上传失败');modal.remove();showToast('理赔材料已上传');openClaimWorkbench(id);}catch(err){uf.querySelector('.auth-error').textContent=err.message;}};}catch(err){showToast(err.message);}}
